import { formatZodErrors } from '@/infra/utils/validation'
import { NextResponse, type NextRequest } from 'next/server'
import type { ZodError } from 'zod'

// Standardized error codes (extensible)
export type ApiErrorCode =
  // Auth errors
  | 'UNAUTHORIZED'
  | 'FORBIDDEN'
  // Validation errors
  | 'VALIDATION_ERROR'
  | 'MISSING_REQUIRED_FIELD'
  // Resource errors
  | 'NOT_FOUND'
  | 'LESSON_NOT_FOUND'
  | 'PROMPT_NOT_FOUND'
  | 'MEDIA_NOT_ATTACHED'
  // Job errors
  | 'JOB_NOT_FOUND'
  | 'JOB_ALREADY_RUNNING'
  | 'JOB_ALREADY_COMPLETED'
  // Rate limiting
  | 'RATE_LIMITED'
  // Upstream errors
  | 'UPSTREAM_ERROR'
  // System errors
  | 'INTERNAL_ERROR'
  | 'SERVICE_UNAVAILABLE'

export interface ApiErrorResponse {
  error: {
    code: ApiErrorCode
    message: string
    details?: Record<string, string[]>
  }
}

export interface ApiSuccessResponse<T = unknown> {
  success: true
  data?: T
  message?: string
}

export function apiError(
  code: ApiErrorCode,
  message: string,
  status: number,
  details?: Record<string, string[]>,
): NextResponse<ApiErrorResponse> {
  return NextResponse.json({ error: { code, message, ...(details && { details }) } }, { status })
}

export function apiSuccess<T>(
  data?: T,
  message?: string,
  status = 200,
): NextResponse<ApiSuccessResponse<T>> {
  return NextResponse.json(
    { success: true, ...(data !== undefined && { data }), ...(message && { message }) },
    { status },
  )
}

export function apiValidationError(error: ZodError): NextResponse<ApiErrorResponse> {
  return apiError('VALIDATION_ERROR', 'Validation failed', 400, formatZodErrors(error))
}

export const ApiErrors = {
  unauthorized: (message = 'Authentication required') => apiError('UNAUTHORIZED', message, 401),
  forbidden: (message = 'Access denied') => apiError('FORBIDDEN', message, 403),
  notFound: (resource: string) => apiError('NOT_FOUND', `${resource} not found`, 404),
  internal: (message = 'Internal server error') => apiError('INTERNAL_ERROR', message, 500),
  rateLimited: (retryAfter?: string) => {
    const response = apiError('RATE_LIMITED', 'Rate limit exceeded. Please try again later.', 429)
    if (retryAfter) {
      response.headers.set('Retry-After', retryAfter)
    }
    return response
  },
  upstreamError: (message = 'Upstream service error') => apiError('UPSTREAM_ERROR', message, 502),

